import { describe, expect, it } from "vitest";
import { buildExperimentsPath, buildExperimentsPathForDataset, buildExperimentsPathForGroup, parseTestRunIds, } from "./openExperiments.js";
const A = "aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa";
const B = "bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb";
const C = "cccccccc-cccc-cccc-cccc-cccccccccccc";
describe("parseTestRunIds", () => {
    it("returns ids from a single comma-separated arg", () => {
        expect(parseTestRunIds([`${A},${B}`])).toEqual([A, B]);
    });
    it("returns ids from multiple separate args", () => {
        expect(parseTestRunIds([A, B, C])).toEqual([A, B, C]);
    });
    it("handles a mix of comma-separated and separate args", () => {
        expect(parseTestRunIds([`${A},${B}`, C])).toEqual([A, B, C]);
    });
    it("trims whitespace around each id", () => {
        expect(parseTestRunIds([` ${A} , ${B} `])).toEqual([A, B]);
    });
    it("deduplicates ids (case-insensitive)", () => {
        expect(parseTestRunIds([A, A.toUpperCase()])).toEqual([A]);
    });
    it("filters out non-UUIDs silently", () => {
        expect(parseTestRunIds([A, "not-a-uuid", "", B])).toEqual([A, B]);
    });
    it("returns an empty array when no valid ids are present", () => {
        expect(parseTestRunIds(["not-a-uuid", ""])).toEqual([]);
        expect(parseTestRunIds([])).toEqual([]);
    });
});
describe("buildExperimentsPath", () => {
    it("builds the path with comma-joined ids", () => {
        expect(buildExperimentsPath([A, B])).toBe(`/studio/experiments?testRunIds=${A}%2C${B}`);
    });
    it("works with a single id", () => {
        expect(buildExperimentsPath([A])).toBe(`/studio/experiments?testRunIds=${A}`);
    });
    it("appends tokens=1&tokenType=all when showTokens is set (default basis)", () => {
        expect(buildExperimentsPath([A], { showTokens: true })).toBe(`/studio/experiments?testRunIds=${A}&tokens=1&tokenType=all`);
    });
    it("omits the tokens param when showTokens is false or absent", () => {
        expect(buildExperimentsPath([A], { showTokens: false })).toBe(`/studio/experiments?testRunIds=${A}`);
        expect(buildExperimentsPath([A], {})).toBe(`/studio/experiments?testRunIds=${A}`);
    });
    it("appends tokenType=uncached for the uncached basis", () => {
        expect(buildExperimentsPath([A], { showTokens: true, tokenType: "uncached" })).toBe(`/studio/experiments?testRunIds=${A}&tokens=1&tokenType=uncached`);
    });
    it("always emits the basis explicitly (tokenType=all) for the default basis", () => {
        expect(buildExperimentsPath([A], { showTokens: true, tokenType: "all" })).toBe(`/studio/experiments?testRunIds=${A}&tokens=1&tokenType=all`);
    });
    it("ignores tokenType when the lens is off (no showTokens)", () => {
        expect(buildExperimentsPath([A], { tokenType: "uncached" })).toBe(`/studio/experiments?testRunIds=${A}`);
    });
});
describe("buildExperimentsPathForGroup", () => {
    it("builds the path with experimentGroupId", () => {
        expect(buildExperimentsPathForGroup(A)).toBe(`/studio/experiments?experimentGroupId=${A}`);
    });
    it("appends tokens=1&tokenType=all when showTokens is set", () => {
        expect(buildExperimentsPathForGroup(A, { showTokens: true })).toBe(`/studio/experiments?experimentGroupId=${A}&tokens=1&tokenType=all`);
    });
    it("emits the uncached basis when requested", () => {
        expect(buildExperimentsPathForGroup(A, {
            showTokens: true,
            tokenType: "uncached",
        })).toBe(`/studio/experiments?experimentGroupId=${A}&tokens=1&tokenType=uncached`);
    });
});
describe("buildExperimentsPathForDataset", () => {
    it("builds the path with datasetId", () => {
        expect(buildExperimentsPathForDataset(A)).toBe(`/studio/experiments?datasetId=${A}`);
    });
    it("appends tokens=1&tokenType=all when showTokens is set", () => {
        expect(buildExperimentsPathForDataset(A, { showTokens: true })).toBe(`/studio/experiments?datasetId=${A}&tokens=1&tokenType=all`);
    });
    it("emits the uncached basis when requested", () => {
        expect(buildExperimentsPathForDataset(A, {
            showTokens: true,
            tokenType: "uncached",
        })).toBe(`/studio/experiments?datasetId=${A}&tokens=1&tokenType=uncached`);
    });
});
